#include<bits/stdc++.h>
using namespace std;
int n,a[1000001],l[1000001],r[1000001],maxn;
int main(){
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
    a[0]=-1;
        a[n+1]=INT_MAX;
    for(int i=1;i<=n;i++){
        if(a[i]>a[i-1]) l[i]=l[i-1]+1;
        else l[i]=1;
    }
	for(int i=n;i>=1;i--){
        if(a[i]<a[i+1]) r[i]=r[i+1]+1;
        else r[i]=1;
    }
    for(int i=1;i<=n;i++){
       maxn = max(maxn,max(l[i-1]+1,r[i+1]+1)); 
        if(a[i+1] - a[i-1] >= 2) maxn = max(maxn,l[i-1]+1+r[i+1]);
    }
	cout<<maxn;
}
